import { NgModule } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { RouterModule } from '@angular/router';
import { AddMenuItemComponent } from './add-menu-item.component';

@NgModule({
    declarations: [AddMenuItemComponent],
    imports: [CommonModule, FormsModule, RouterModule.forChild([{ path: '', component: AddMenuItemComponent }])]
})
export class AddMenuItemModule { }
